const incoming = $input.first().json;
const body = incoming.body ?? incoming;
const routing = body.routing ?? {};
const urgency = typeof body.urgency === 'string' ? body.urgency : 'medium';
const proposedTasks = Array.isArray(body.proposedTasks) ? body.proposedTasks : [];
const secondary = Array.isArray(routing.secondary) ? routing.secondary : [];

return [{
  json: {
    id: body.id ?? '',
    capturedAt: body.capturedAt ?? new Date().toISOString(),
    text: body.text ?? '',
    analysis: body.analysis ?? '',
    routing: {
      primary: routing.primary ?? 'chief',
      secondary,
      category: routing.category ?? 'Admin',
    },
    urgency,
    proposedTasks,
  },
}];

const item = $input.first().json;
const text = typeof item.text === 'string' ? item.text.trim() : '';
const words = text.split(/\s+/).filter(Boolean);
const title = words.length <= 10 ? text : `${words.slice(0, 10).join(' ')}...`;
const primary = item.routing.primary;
const category = item.routing.category;
const urgency = item.urgency;
const escalation = ['critical', 'high'].includes(urgency);

const domainTemplates = {
  meals: [
    'Generate a practical meal plan for the next few days',
    'Build or refine the grocery list',
    'Block prep time and confirm constraints'
  ],
  home: [
    'Confirm the failure mode and troubleshooting steps',
    'Check warranty, vendor history, and next action',
    'Escalate to quote gathering if unresolved'
  ],
  money: [
    'Review the account or bill context',
    'Draft the payment or budget adjustment',
    'Escalate if spend or risk threshold is exceeded'
  ],
  schedule: [
    'Find available windows and conflicts',
    'Propose a concrete scheduling action',
    'Confirm calendar updates after approval'
  ],
  roster: [
    'Capture the people and relationships involved',
    'Draft the follow-up plan',
    'Coordinate communication across the household'
  ],
  chief: [
    'Ask one clarifying question if context is incomplete',
    'Prepare the item for human review',
    'Hold pending approval or next routing decision'
  ],
};

const fallbackAnalysis = `n8n reviewed the intake and confirmed ${primary} as the primary domain.`;
const refinedAnalysis = item.analysis || fallbackAnalysis;
const proposedTasks = item.proposedTasks.length > 0 ? item.proposedTasks : (domainTemplates[primary] ?? domainTemplates.chief);

return [{
  json: {
    ...item,
    title: title || `${category} intake`,
    refinedAnalysis,
    proposedTasks,
    needsAction: true,
    inboxStatus: escalation ? 'processing' : 'processed',
    escalation,
    alertSummary: escalation ? `${urgency.toUpperCase()}: ${title || text}` : '',
  },
}];

const item = $input.first().json;
return [{
  json: {
    ok: true,
    eventType: 'chief_of_staff.intake.processed',
    id: item.id,
    inboxStatus: item.inboxStatus,
    escalation: Boolean(item.escalation),
    alertSummary: item.alertSummary || '',
    supabaseUpdated: true,
    routing: item.routing,
    urgency: item.urgency,
    proposedTasks: item.proposedTasks,
    processedAt: new Date().toISOString(),
  },
}];
